import { createElement } from 'react';
import ReactDOM from 'react-dom/client';
import React, { memo, useEffect, useRef } from '../../../lib/teact/teact';
import { withGlobal } from '../../../global';

import type { AgentSelectedMessage } from '../agent/types';

import { selectTabState } from '../../../global/selectors';
import { getCurrentTabId } from '../../../util/establishMultitabRole';
import { useRoomAIStore } from '../store/zustand/room-ai-store';
import RoomAI from './room-ai';

interface OwnProps {
  chatId: string | undefined;
}

interface StateProps {
  selectedMessages?: AgentSelectedMessage[];
}

const RoomAIWrapper = ({ chatId, selectedMessages }: OwnProps & StateProps) => {
  const containerRef = useRef<HTMLDivElement>();
  const rootRef = useRef<ReturnType<typeof ReactDOM.createRoot>>();

  // Mount React root once
  useEffect(() => {
    if (!containerRef.current) return undefined;
    rootRef.current = ReactDOM.createRoot(containerRef.current);
    rootRef.current.render(createElement(RoomAI));
    return () => {
      rootRef.current?.unmount();
      rootRef.current = undefined;
    };
  }, []);

  // Sync Teact props → Zustand store
  useEffect(() => {
    useRoomAIStore.getState().setChatId(chatId);
  }, [chatId]);

  useEffect(() => {
    useRoomAIStore.getState().setSelectedMessages(selectedMessages ?? []);
  }, [selectedMessages]);

  return <div className="chat-ai-room flex overflow-hidden" ref={containerRef} />;
};

export default memo(withGlobal<OwnProps>(
  (global): StateProps => {
    const tabId = getCurrentTabId();
    const tabState = selectTabState(global, tabId);
    return {
      selectedMessages: tabState.chatAISelectedMessages,
    };
  },
)(RoomAIWrapper));
