/**
 * SingleChat Messages WebSocket Handler (Client Side)
 *
 * 对应服务端 single-chat-messages.ts，处理 scm_* 消息：
 * - 响应类：scm_insert_response / scm_upsert_response / scm_delete_response / scm_sync_response
 * - 远端广播类：scm_remote_insert / scm_remote_upsert / scm_remote_delete
 *
 * 同时提供发送接口：sendSCMInsert / sendSCMUpsert / sendSCMDelete / sendSCMSync
 */

import type { SyncChatMessage } from '../../../messages/types';

import { getMcpWebSocket } from '../mcp-websocket';

// ===========================
// 类型定义
// ===========================

export interface SCMMessageData {
  serverId?: number;
  localId?: string;
  chatId: string;
  messageType: string;
  userMessage: string;
  aiResponse: string;
  timestamp: number;
  metadata?: Record<string, any>;
}

export interface SCMInsertPayload extends Omit<SCMMessageData, 'serverId'> {
  localId: string;
}

export interface SCMUpsertPayload extends SCMMessageData {
  localId: string;
}

export interface SCMDeletePayload {
  serverId?: number;
  localId?: string;
}

export interface SCMSyncPayload {
  chatId: string;
  sinceId?: number;
  limit?: number;
}

// 响应体
export interface SCMInsertResponse {
  type: 'scm_insert_response';
  requestId: string;
  success: boolean;
  data?: { serverId: number; localId: string };
  error?: string;
}

export interface SCMUpsertResponse {
  type: 'scm_upsert_response';
  requestId: string;
  success: boolean;
  data?: { serverId: number; localId: string };
  error?: string;
}

export interface SCMDeleteResponse {
  type: 'scm_delete_response';
  requestId: string;
  success: boolean;
  data?: { serverId: number; localId: string };
  error?: string;
}

export interface SCMSyncResponse {
  type: 'scm_sync_response';
  requestId: string;
  success: boolean;
  data?: {
    messages: SCMMessageData[];
    hasMore: boolean;
    nextSinceId: number;
  };
  error?: string;
}

// 远端广播消息
export interface SCMRemoteInsert {
  type: 'scm_remote_insert';
  data: SCMMessageData & { serverId: number; localId: string };
}

export interface SCMRemoteUpsert {
  type: 'scm_remote_upsert';
  data: SCMMessageData & { serverId: number; localId: string };
}

export interface SCMRemoteDelete {
  type: 'scm_remote_delete';
  data: { serverId: number; localId: string; chatId: string };
}

export type SCMResponse =
  | SCMInsertResponse
  | SCMUpsertResponse
  | SCMDeleteResponse
  | SCMSyncResponse;

export type SCMRemoteMessage = SCMRemoteInsert | SCMRemoteUpsert | SCMRemoteDelete;

function genRequestId() {
  return `scm_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
}

function send(payload: Record<string, any>): boolean {
  const ws = getMcpWebSocket();
  if (!ws) {
    // eslint-disable-next-line no-console
    console.warn('[SCM] WebSocket not available');
    return false;
  }
  return ws.send(payload);
}

function toSCMMessageData(data: SyncChatMessage): SCMMessageData {
  return {
    chatId: data.chatId,
    localId: data.id,
    messageType: data.type,
    userMessage: data.role === 'user' ? data.content ?? '' : '',
    aiResponse: data.role === 'assistant' ? data.content ?? '' : '',
    metadata: data.metadata,
    timestamp: data.timestamp,
  };
}

export function sendSCMInsert(
  data: SyncChatMessage,
) {
  const requestId = genRequestId();
  const payload = toSCMMessageData(data);
  send({ type: 'scm_insert', requestId, data: payload });
}

export function sendSCMUpsert(
  data: SyncChatMessage,
) {
  const requestId = genRequestId();
  const payload = toSCMMessageData(data);
  send({ type: 'scm_upsert', requestId, data: payload });
}

export function sendSCMDelete(
  data: SCMDeletePayload,
) {
  const requestId = genRequestId();
  send({ type: 'scm_delete', requestId, data });
}
